
import React, { useState, useEffect } from "react";

import "./styles.css"
import "./PLanOfferTabs.css"
import { SvgIcon_Cmpt, LoadingColorSpinner_Cmpt, CalendarModalPicker_Cmpt } from "../../../components";
import { parseQuery, getStore, gen16CodeId, ObjectKeys, qryKprofile, updStore, tokenNameCookie, callDispatchEvent } from "../../../stores/Utils";
import {  useLocation } from "react-router";
import { NavLink } from "react-router-dom";
import loadable from "@loadable/component";

import { fetchNotaryItem } from "../services/services";

import { OpenModal } from "../../../components/DialogHRM";
import { updFsObjByColl } from "../../../stores/fb_services";
import { CustomerLoadFile_Cmpt } from "..";


// import DDDD from "../services/docs/test_h.json"


const GSingin =  loadable(() => import("../../../services/googleSingIn"));

const Svg = SvgIcon_Cmpt();

const LoadingColorSpinner = LoadingColorSpinner_Cmpt();


const CalendarModalPicker = CalendarModalPicker_Cmpt();
const CustomerLoadFile = CustomerLoadFile_Cmpt();





const NotaryDashboard  = ({ data, confirm, label, item }) => {

	// const { modalID } = data;

	const [info, setInfo] = useState({});
	const [id, setId] = useState(null);
	const [obs, set_obs] = useState(1);
	const [init, setInit] = useState(false);
	let location = useLocation();
	//const navigate = useNavigate();
	const searchHash = location.search?.split("?")?.[1];
	const router = parseQuery(searchHash);
	useEffect(() => {
		if(!init){
			if(router?.sId && id!==router?.sId){
				if(getStore(router?.sId)){
					updObs(getStore(router?.sId));
				}
				else{
					fetchNotaryItem(router?.sId,"notary_item_"+router?.sId, updObs, router?.k);
					window.scrollTo(0,0)
					setId(router?.sId);
				}
			}
			setInit(true);
		}
	},[location]);



	const updObs =  (v) => {
		v && updStore(router?.sId, v);
		v && setInfo(v);
		//console.log(JSON.stringify(ffff))
		set_obs(gen16CodeId());
    }
	
	const confirmCalendar =  (v) => {


		//console.log(v)	
		if(v.initDate){
			let dateC = new Date(v.initDate);
			let yy = dateC.getFullYear();
			let mm = dateC.getMonth();
			let dd = dateC.getDate();
			let mmKey = yy+"_"+mm;
			let dayKey = yy+"_"+mm+"_"+dd;
			let appKey = "app_"+v.appTimeSelected;
			let obj = {
				[appKey] : {
					userId: getStore(qryKprofile()).userId,
					service: router?.sId
				}
			};
			updFsObjByColl(mmKey,dayKey,obj);
		}
		
		set_obs(gen16CodeId());
	}
	
	const recallCalendar =  (v) => {
		set_obs(gen16CodeId());
	}
	
	const logout =  (v) => {
		document.cookie = `${tokenNameCookie()}=""`;
		document.cookie = `stephaniesg_access_tkn = ""`;
		updStore(qryKprofile(),null)
		updStore("isAdmin",null);
		callDispatchEvent("isLogged_987");
		
	}
		
	
	const openCalendar = () => {
        let modal_data = {};
        modal_data["zIndex"] = 950;
        modal_data["height"] = "80vh";
        // data['observeResize']=true;
		modal_data["props"] = { minHeight: "1vh", overlay: true };
		if(getStore(qryKprofile())?.email){
			modal_data["content"] = 
			<CalendarModalPicker 
				onConfirm={confirmCalendar} 
				init={getStore("date_range_comps")?.initDate}
				appoitmentType={true}
				//last={getStore("date_range_comps")?.lastDate}
				//isRange={true}
			/>
		}else{
			modal_data["content"] = <GSingin callback={openCalendar}/>
		}
        OpenModal(modal_data);
	}
   
	

	const openUploadView = () => {
        let modal_data = {};
        modal_data["zIndex"] = 950;
        modal_data["height"] = "80vh";
        // data['observeResize']=true;
		modal_data["props"] = { minHeight: "1vh", overlay: true };
		if(getStore(qryKprofile())?.email){
			updStore( "preview_src",null);
			updStore( "preview_dmz",null);
			updStore( "file_type_upload",null);
			modal_data["content"] = <CustomerLoadFile />
		}else{
			modal_data["content"] = <GSingin callback={openCalendar}/>
		}
        OpenModal(modal_data);
	}
   
	



    return (
       
		<div >
			
			<div className="_dsplFlx  " style={{width: "100%"}}>
				<div className="_dsplFlx header_mobile ">
					<div className="nav_title_header " >
						<NavLink className="_dsplFlx "  to={"/"}>
							<div className="logo_ssg  ">
								<img src={"https://stephaniesolutiong.com/favicon.png"} alt={"logo"}/>
								
							</div>
							<span className="jaqJnq bVyKiY hiddeOnMobile">
								{"Stephanie Solution Group"}
							
							</span>
							
						</NavLink>
					</div>
					<div className="nav_title_dot">
						•
					</div>
					<p className="nav_title_header sub_nav" >
						<NavLink className=" jaqJnq"  to={"/notary-services"}>
						{"Servicio de Notaria"}
						</NavLink>
					</p>
					<div className="flexSpace"/>
					<p className="lbl_prod_header"></p>
				</div>
				<div className="flexSpace"/>
				{getStore(qryKprofile())?.picture?
				<div className="icon_account_logo  " onClick={logout}>
					
					<img src={getStore(qryKprofile())?.picture} alt={"logo"}/>
					
				</div>
				:null}
			</div>

			<div className="_dsplFlx " >
				<div className="flexSpace"/>
				<div style={{width: 230}}>
					<button 
						fontSize="var(--body-3-d)" 
						width="100%" 
						height="40px" 
						className="eFUBzq VGvzR  kVpBQj" 
						mode="primaryLight"
						onClick={openCalendar}
					>
						Hacer un cita
					</button>
				</div>
				<div className="flexSpace"/>
				{getStore(qryKprofile())?.isAdmin?
				<div style={{width: 230}}>
					<button 
						fontSize="var(--body-3-d)" 
						width="100%" 
						height="40px" 
						className="eFUBzq VGvzR  kVpBQj" 
						mode="primaryLight"
						onClick={openUploadView}
					>
						Subir Documentos
					</button>
				</div>
				:null}
				<div className="flexSpace"/>
			</div>


			{info.title?
			
			<div>
			<div className="listFlx spaceAround flxWrp w_100prc" >
				<div className="code_prod_header _dsplFlx">
					<div className="fxOkFE"  >
					{info?.title}
					</div>
				
					<div style={{marginLeft:13}} className="fxOkFE"  >
					{info?.title2}
					</div>
				
				</div>
				
				<div className="listFlx spaceAround" >
					
					<div className="jMkcoP" style={{marginTop:30}}>
						<div className="flexOnM"/>
						<h2 className="fxOkFE lixTxu">
							{info.disconunt ?  <span  className="hzYytG jreNbN">${info.disconunt}</span> : null}
							<span  className="">${info.price}</span>
						</h2>
						<div className="jVaMjA kASDvd">{info.unit	}</div>
					</div>
					<div className="flexSpace"/>
				</div>
			</div>


			<div className="listFlx spaceAround flxWrp w_100prc" >
				

				{info?.elements && info.elements.map(elm=>{
					return (
						<CardM3 
							elm={elm}
							key={elm.key2Show}
						/>	
					)
				})}
			</div>
		</div>
			:
		<div  className={"loading_app"}>
			<LoadingColorSpinner stroke={"#646cff"} size={94} strokeW={3}/>

		</div>
			}
		</div>
    )   
}

export default NotaryDashboard;





const CardM3 = ({elm}) =>{
	

	return (
		<div className={`${elm.horizontal?"hrz":""}`}  style={{margin: 8}}>
			<div type="Free"  className={`idfmDQ`}>
				<div  className={` gPHWco`} >
					<div className={`dcXXTq `} >
						{elm?.section && elm?.section.map((sect, inSec)=>{

							if(sect.type==="title"){
								return <TitleSection
									key={inSec+"_sec_dtcmp"}
									data={sect?.data}
								/>
							}
							else if(sect.type==="body"){
								return <BodySection
									key={inSec+"_sec_dtcmp"}
									data={sect?.data}
									show={true}
									horizontal={elm.horizontal}
								/>
							}
							else if(sect.type==="title"){
								return <div className="dHZVrX" 
									key={inSec+"_sec_dtcmp"}
								/>
							}
							return null;
						})}
					</div>
				</div>
			</div>

    
		</div>
	)

}




const TitleSection  = ({ data }) => {

	return (
		<div className="cLSEHF">
			<div className="icon_revision" >
				{data?.icon?
				<Svg 
					name={data?.icon.name} 
					color={data?.icon.color}
				/>
				:null}
			</div>
			<div  className="eKdSaJ">
				<div className=" jVaMjA dBwXbT">{data?.label}</div>
			</div>
			<div className="flexSpace"/>
		</div>
	)

}


const BodySection  = ({ data, show, horizontal }) => {

	return (
		<div className={`wLSEHTr ${horizontal?"_dsplFlx flxWrp":""}`} style={{maxHeight: show ? "100%": 0 }}>
			{data?.map((desW, inw2)=>{
				let marginR  = desW.marginL?{marginLeft:desW.marginL}:null;
				return(
					<div className={`cLSEHF ${horizontal?"horz_mw":""}`}  style={marginR} key={inw2+"_bdy_sc_det"}>
						<div className="icon_revision" >
							{desW.icon?
							<Svg 
								name={desW.icon.name} 
								color={desW.icon.color}
							/>
							:null}
						</div>
						<div data-test-id="Wrapper" className=" eKdSaJ" >
							<div className="jVaMjA dBwXbT">{desW.label}</div>
							{desW.details && desW.details.map((detail, indDt)=>{
								return (
								<div className="igLyC bmhZKY _dsplFlx" key={indDt +"__bdy_sc_det_"+inw2}> 
									<div className="pnt_mrkr">
										•
									</div>
									{detail.hasLink?
										<NavLink className=" jaqJnq bVyKiY"  to={detail.link2}>
											{detail.label}
										</NavLink>
									:
									detail.hasExtLink?
										<div className="jaqJnq " onClick={()=>window.open(detail.link2)}>
											{detail.label}
										</div>
									:
									<span>
										{detail.label}
									</span>
									}
								</div>)
							})}
						</div>
					</div>
				)
			})}
		</div>
	)

}





